// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @notice Soulbound Token — non-transferable ERC-721. Override _update to block transfers.
contract CelestialSBT {
    string public name = "Meta Go Sovereign ID";
    string public symbol = "MGSID";
    uint256 private _nextTokenId = 1;

    mapping(uint256 => address) public ownerOf;
    mapping(address => uint256) public balanceOf;
    mapping(uint256 => string) public domainOf;
    mapping(uint256 => bool) public revoked;
    mapping(uint256 => string) public tokenURIs;

    event Minted(address indexed to, uint256 indexed tokenId, string domain);
    event Revoked(uint256 indexed tokenId);

    function mint(address to, string calldata domain, string calldata uri) external returns (uint256) {
        require(to != address(0), "Mint to zero");
        uint256 tokenId = _nextTokenId++;
        ownerOf[tokenId] = to;
        balanceOf[to]++;
        domainOf[tokenId] = domain;
        tokenURIs[tokenId] = uri;
        emit Minted(to, tokenId, domain);
        return tokenId;
    }

    function revoke(uint256 tokenId) external {
        require(ownerOf[tokenId] != address(0), "Token not found");
        revoked[tokenId] = true;
        emit Revoked(tokenId);
    }

    /// @notice Soulbinding — transfer is permanently disabled at protocol level.
    function transferFrom(address, address, uint256) external pure {
        revert("SOULBOUND: transfer disabled");
    }
    function safeTransferFrom(address, address, uint256) external pure {
        revert("SOULBOUND: transfer disabled");
    }
    function safeTransferFrom(address, address, uint256, bytes calldata) external pure {
        revert("SOULBOUND: transfer disabled");
    }
    function approve(address, uint256) external pure {
        revert("SOULBOUND: approval disabled");
    }
    function setApprovalForAll(address, bool) external pure {
        revert("SOULBOUND: approval disabled");
    }
}

contracts/CredentialVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract CredentialVault {
    struct Credential {
        string vcType;
        bytes32 vcHash;
        string ipfsURI;
        uint64 issuedAt;
        bool revoked;
        address issuer;
    }

    mapping(address => mapping(bytes32 => Credential)) public vault;

    event CredentialIssued(address indexed holder, bytes32 indexed vcId, address indexed issuer);
    event CredentialRevoked(address indexed holder, bytes32 indexed vcId);

    function issueCredential(
        address holder,
        bytes32 vcId,
        string calldata vcType,
        bytes32 vcHash,
        string calldata ipfsURI
    ) external {
        vault[holder][vcId] = Credential({
            vcType: vcType,
            vcHash: vcHash,
            ipfsURI: ipfsURI,
            issuedAt: uint64(block.timestamp),
            revoked: false,
            issuer: msg.sender
        });
        emit CredentialIssued(holder, vcId, msg.sender);
    }

    function revokeCredential(address holder, bytes32 vcId) external {
        require(vault[holder][vcId].issuer == msg.sender, "Only issuer can revoke");
        vault[holder][vcId].revoked = true;
        emit CredentialRevoked(holder, vcId);
    }
}

